import os
from src.polaris_graph.settings import get_entailment_model, get_max_docling_pdf_bytes, get_v6_redis_url

# byte-identical parity: accessor == original os.getenv expression, unset and set
def orig_entail(): return os.environ.get('PG_ENTAILMENT_MODEL', 'z-ai/glm-5.2')
def orig_docling(): return int(os.getenv('PG_MAX_DOCLING_PDF_BYTES', str(5*1024*1024)))
def orig_redis(): return os.environ.get('POLARIS_V6_REDIS_URL', 'redis://localhost:6379/0')

for env in ({}, {'PG_ENTAILMENT_MODEL':'x/y','PG_MAX_DOCLING_PDF_BYTES':'123','POLARIS_V6_REDIS_URL':'redis://h:1/2'}):
    for k in ('PG_ENTAILMENT_MODEL','PG_MAX_DOCLING_PDF_BYTES','POLARIS_V6_REDIS_URL'):
        os.environ.pop(k, None)
    os.environ.update(env)
    assert get_entailment_model()==orig_entail(), (get_entailment_model(), orig_entail())
    assert get_max_docling_pdf_bytes()==orig_docling()
    assert get_v6_redis_url()==orig_redis()
    print('parity ok for env keys set:', list(env.keys()))

# coercion: bad int raises ValueError exactly like inline int()
os.environ['PG_MAX_DOCLING_PDF_BYTES']='notanint'
try:
    get_max_docling_pdf_bytes(); print('FAIL: no raise')
except ValueError: print('ValueError raised as expected on bad int')
print('ALL PARITY OK')
